#include "engine/orb/messages/InvokeMethodMessage.h"


ShipComponentAdapter::ShipComponentAdapter(ShipComponent* obj) : ComponentAdapter(obj) {
}

void ShipComponentAdapter::invokeMethod(uint32 methid, DistributedMethod* inv) {
	DOBMessage* resp = inv->getInvocationMessage();

	switch (methid) {
	case RPC_GETCOMPONENTDATANAME__:
		{
			
			String _m_res = getComponentDataName();
			resp->insertAscii(_m_res);
		}
		break;
	case RPC_GETCOMPONENTBITMASK__:
		{
			
			unsigned int _m_res = getComponentBitmask();
			resp->insertInt(_m_res);
		}
		break;
	case RPC_GETEFFICIENCY__:
		{
			
			float _m_res = getEfficiency();
			resp->insertFloat(_m_res);
		}
		break;
	case RPC_GETENERGYEFFICIENCY__:
		{
			
			float _m_res = getEnergyEfficiency();
			resp->insertFloat(_m_res);
		}
		break;
	case RPC_GETMASS__:
		{
			
			float _m_res = getMass();
			resp->insertFloat(_m_res);
		}
		break;
	case RPC_GETMAXHITPOINTS__:
		{
			
			float _m_res = getMaxHitpoints();
			resp->insertFloat(_m_res);
		}
		break;
	case RPC_GETHITPOINTS__:
		{
			
			float _m_res = getHitpoints();
			resp->insertFloat(_m_res);
		}
		break;
	case RPC_GETMAXARMOR__:
		{
			
			float _m_res = getMaxArmor();
			resp->insertFloat(_m_res);
		}
		break;
	case RPC_GETARMOR__:
		{
			
			float _m_res = getArmor();
			resp->insertFloat(_m_res);
		}
		break;
	case RPC_GETENERGYCOST__:
		{
			
			float _m_res = getEnergyCost();
			resp->insertFloat(_m_res);
		}
		break;
	case RPC_GETCOLLISIONRANGE__:
		{
			
			float _m_res = getCollisionRange();
			resp->insertFloat(_m_res);
		}
		break;
	case RPC_GETREVERSEENGINEERINGLEVEL__:
		{
			
			int _m_res = getReverseEngineeringLevel();
			resp->insertSignedInt(_m_res);
		}
		break;
	case RPC_HASCOMPONENTFLAG__INT_:
		{
			unsigned int value = inv->getUnsignedIntParameter();
			
			bool _m_res = hasComponentFlag(value);
			resp->insertBoolean(_m_res);
		}
		break;
	case RPC_ISSHIPCOMPONENTOBJECT__:
		{
			
			bool _m_res = isShipComponentObject();
			resp->insertBoolean(_m_res);
		}
		break;
	default:
		ComponentAdapter::invokeMethod(methid, inv);
	}
}

