void ShipComponentPOD::readObject(ObjectInputStream* stream) {
	uint16 _varCount = stream->readShort();
	for (int i = 0; i < _varCount; ++i) {
		uint32 _nameHashCode;
		TypeInfo<uint32>::parseFromBinaryStream(&_nameHashCode, stream);

		uint32 _varSize = stream->readInt();

		int _currentOffset = stream->getOffset();

		if(ShipComponentPOD::readObjectMember(stream, _nameHashCode)) {
		}

		stream->setOffset(_currentOffset + _varSize);
	}

}

void ShipComponentPOD::writeObjectCompact(ObjectOutputStream* stream) {
	ComponentPOD::writeObjectCompact(stream);

	TypeInfo<float >::toBinaryStream(&mass.value(), stream);

	TypeInfo<float >::toBinaryStream(&hitpointsMax.value(), stream);

	TypeInfo<float >::toBinaryStream(&armorMax.value(), stream);

	TypeInfo<float >::toBinaryStream(&hitpoints.value(), stream);

	TypeInfo<float >::toBinaryStream(&armor.value(), stream);

	TypeInfo<float >::toBinaryStream(&energyCost.value(), stream);

	TypeInfo<float >::toBinaryStream(&energyEfficiency.value(), stream);

	TypeInfo<float >::toBinaryStream(&efficiency.value(), stream);

	TypeInfo<float >::toBinaryStream(&collisionRange.value(), stream);

	TypeInfo<unsigned int >::toBinaryStream(&componentBitmask.value(), stream);

	TypeInfo<int >::toBinaryStream(&componentSlot.value(), stream);

	TypeInfo<int >::toBinaryStream(&reverseEngineeringLevel.value(), stream);

	TypeInfo<ManagedWeakReference<ShipObjectPOD* > >::toBinaryStream(&componentShip.value(), stream);

	TypeInfo<String >::toBinaryStream(&componentDataName.value(), stream);


}

